#include <bits/stdc++.h>
using namespace std;
long long n,a,k,b;

int main(){
	cin>>n>>a>>k>>b;
	if(n%2!=0){
		cout<<-1<<endl;
		return 0;
	}
	long long half = n/2;

	if(a*k<=b){
		cout<<n*a<<endl;
	}else if(a>b){
		cout<<((half+k-1)/k)*b*2<<endl;
	}else{
		long long count = 0;
		count+=(half/k)*b;
		if((half%k)*a<=b){
			count+=half%k*a;
		}else{
			count+=b;
		}
		cout<<count*2<<endl;
	}
	return 0;
}
